SELECT student_id
FROM registration_logs
WHERE action = 'enroll' AND log_date > '2023-01-01';

SELECT students.name
FROM students
WHERE students.student_id IN (SELECT student_id FROM waitlists);

SELECT name
FROM instructors
WHERE office_hours = (SELECT MIN(office_hours) FROM instructors);

SELECT COUNT(action) AS enroll_actions
FROM registration_logs
WHERE student_id = 1 AND action = 'enroll';

SELECT action, COUNT(*) AS action_count
FROM registration_logs
GROUP BY action;
